option.value:
/*
 * CustomTable — structural / layout base styles.
 * No colors, backgrounds, shadows, or border-colors here.
 * Theme files provide visual appearance via CSS custom properties.
 */

.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

.custom-table {
  overflow: hidden;
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  user-select: none;
  display: flex;
  flex-direction: column;

  table {
    font-size: var(--font-size);line-height: var(--line-height);
  }

  th {
    font-weight: 400;
  }

  &:focus {
    outline: none;
  }

  &.pending {
    pointer-events: none;
    opacity: 0.6;
  }

  &.has-ellipsis .cell {
    white-space: nowrap;
  }

  /* Toolbar */
  .custom-table-toolbar {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 6px 10px;
    flex-shrink: 0;
  }

  /* Viewport / scroll area */
  .custom-table-viewport {
    position: relative;
    flex: 1;
    overflow: auto;
    display: grid;
  }

  table {
    border-collapse: collapse;
    border: none;
  }

  .custom-table-table {
    width: 100%;
  }

  /* Sticky positioning */
  thead th {
    position: sticky;
    top: 0px;
    z-index: 3;

    &.sticky {
      left: 0px;
      z-index: 4;
    }
  }

  tbody td.sticky {
    position: sticky;
    z-index: 3;
  }

  /* Cell / column header layout */
  .col-header,
  .cell {
    padding-top: 6px;
    padding-bottom: 6px;
    padding-right: 20px;
    padding-left: 10px;
  }

  .cell {
    position: relative;

    .cell-dropdown-indicator {
      position: absolute;
      right: 5px;
      top: 50%;
      transform: translateY(-50%);
      font-size: var(--font-size);line-height: var(--line-height);
      pointer-events: none;
      line-height: 1;
    }
  }

  .cell-popup-indicator {
    position: absolute;
    right: 5px;
    top: 50%;
    transform: translateY(-50%);
    font-size: var(--font-size);line-height: var(--line-height);
    cursor: pointer;
    pointer-events: auto;
    line-height: 1;
  }

  .col-edited,
  .cell-edited {
    user-select: all;
  }

  .cell-selected,
  .cell-edited {
    z-index: 1;
  }

  /* Selection / fill rectangles */
  .fill-rectangle,
  .selection-rectangle {
    display: none;
    position: absolute;
    pointer-events: none;
  }

  #selection-rectangle,
  #fill-rectangle {
    z-index: 2;
  }

  #selection-rectangle-sticky,
  #fill-rectangle-sticky {
    position: absolute;
    z-index: 2;
  }

  .selection-rectangle-dragger {
    content: "";
    width: 8px;
    height: 8px;
    position: absolute;
    right: -5px;
    bottom: -5px;
    pointer-events: all;
    z-index: 20;
    cursor: crosshair;
  }

  /* Context menu structure */
  .context-menu {
    position: absolute;
    border-radius: 5px;
    padding: 10px;
    z-index: 1000;
    /* top/left/visibility are set dynamically via inline styles in the component */
  }

  /* Portal wrapper used by ContextMenu to avoid affecting document flow */
  .context-menu-portal {
    display: contents;
  }

  .context-menu-shortcut {
    padding-left: 4rem;
  }

  .context-menu-item {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 5px 20px;
    cursor: pointer;
    white-space: nowrap;
  }

  .context-menu-modal-background {
    position: fixed;
    top: 0;
    right: 0;
    bottom: 0;
    left: 0;
    z-index: 999;
  }

  /* Column header layout */
  .col-header-content {
    display: flex;
    flex-direction: column;
    gap: 4px;
    /* center the label horizontally but allow filter/input to stretch */
    align-items: center;
  }

  .col-header-label {
    cursor: pointer;
    white-space: nowrap;
    /* only as wide as its text */
    display: inline-block;
    padding: 0 0.25rem;
    text-align: center;
  }

  /* Filter input */
  .col-filter-input {
    width: calc(100% + 20px);
    margin-left: -6px;
    margin-right: -6px;
    box-sizing: border-box;
    padding: 2px 4px;
    border-radius: 2px;
    font-size: var(--font-size);line-height: var(--line-height);
    font-family: inherit;
    /* ensure input stretches to column width even when parent centers items */
    align-self: stretch;
  }

  /* Editor input */
  .cell-editor-input {
    width: 100%;
    box-sizing: border-box;
    border: none;
    outline: none;
    background: transparent;
    color: inherit;
    font: inherit;
    padding: 0;
    margin: 0;
  }

  /* Number editor wrapper */
  .number-editor-wrapper {
    display: inline-flex;
    align-items: baseline;
    width: 100%;

    &::before {
      content: attr(data-prefix);
      white-space: pre;
      flex-shrink: 0;
    }

    &::after {
      content: attr(data-suffix);
      white-space: pre;
      flex-shrink: 0;
    }

    .cell-editor-input {
      flex: 1;
      min-width: 0;
    }
  }

  /* Alignment helpers */
  .cell-align-right {
    text-align: right;

    .cell-editor-input {
      text-align: right;
    }
  }

  .cell-align-center {
    text-align: center;

    .cell-editor-input {
      text-align: center;
    }
  }

  /* Combobox dropdown layout */
  .combo-dropdown {
    position: relative;
    outline: none;
  }

  .combo-dropdown-display {
    min-height: 1em;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
  }

  .combo-dropdown-list {
    position: absolute;
    top: 100%;
    left: -10px;
    min-width: calc(100% + 30px);
    border-radius: 4px;
    z-index: 200;
    padding: 4px 0;
    max-height: 220px;
    overflow-y: auto;
  }

  .combo-dropdown-option {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 5px 12px;
    cursor: pointer;
    font-size: var(--font-size);line-height: var(--line-height);
    user-select: none;

    &.is-custom {
      font-style: italic;
    }
  }

  .combo-dropdown-custom-badge {
    margin-left: auto;
    font-size: var(--font-size);line-height: var(--line-height);
    font-style: normal;
    white-space: nowrap;
    flex-shrink: 0;
  }

  .combo-dropdown-checkbox {
    font-size: var(--font-size);line-height: var(--line-height);
    flex-shrink: 0;
  }

  .combo-dropdown-input {
    display: block;
    width: 100%;
    box-sizing: border-box;
    border: none;
    outline: none;
    background: transparent;
    font: inherit;
    font-size: var(--font-size);line-height: var(--line-height);
    padding: 0;
    margin: 0;
  }

  .combo-dropdown-empty {
    padding: 6px 12px;
    font-size: var(--font-size);line-height: var(--line-height);
    font-style: italic;
  }
}

/* Pagination structure */
.ct-pagination {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 6px 10px;
  font-size: var(--font-size);line-height: var(--line-height);
  flex-shrink: 0;
  flex-wrap: wrap;

  .ct-pagination-label {
    white-space: nowrap;
  }

  .ct-pagination-pages {
    display: flex;
    align-items: center;
    gap: 2px;
    flex-wrap: wrap;
  }

  .ct-pagination-page {
    min-width: 28px;
    height: 28px;
    padding: 0 4px;
    border-radius: 3px;
    background: none;
    cursor: pointer;
    font-size: var(--font-size);line-height: var(--line-height);
    line-height: 1;

    &.is-current {
      cursor: default;
    }
  }

  .ct-pagination-select {
    height: 28px;
    padding: 0 4px;
    border-radius: 3px;
    font-size: var(--font-size);line-height: var(--line-height);
    cursor: pointer;
  }
}


.ct-pagination-ellipsis {
  padding: 0 2px;
  user-select: none;
  line-height: 28px;
}


.toolbar-input {
  width: 60px;
  padding: 4px 8px;
  border-radius: 3px;
  font-size: var(--font-size);line-height: var(--line-height);
}

.toolbar-button {
  border: 1px solid var(--ct-button-border);
  background-color: var(--ct-button-bg);
  color: var(--ct-text);
  &:hover {
    background-color: var(--ct-button-hover);
  }
  padding: 4px 12px;
  border-radius: 3px;
  cursor: pointer;
  font-size: var(--font-size);line-height: var(--line-height);

  &:disabled {
    opacity: 0.4;
    cursor: default;
  }


  &.toggle {
    border: 1px outset var(--ct-border);
    &.active {
      border: 1px inset var(--ct-border);
      background-color: var(--ct-dropdown-both);
    }
  }
}

/* Editor Dialog structure (used for Textarea, Subtable, etc.) */
.editor-dialog-overlay {
  position: fixed;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 10000;
}

.editor-dialog {
  border-radius: 8px;
  width: min(1200px, 90vw);
  display: flex;
  flex-direction: column;
  max-height: 90vh;

  .editor-dialog-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 12px 16px;
  }

  .editor-dialog-title {
    font-weight: 600;
    font-size: var(--font-size);line-height: var(--line-height);
  }

  .editor-dialog-close {
    background: none;
    border: none;
    font-size: 1.4rem;
    cursor: pointer;
    padding: 0 4px;
    line-height: 1;
  }

  .editor-dialog-input {
    flex: 1;
    margin: 16px 20px;
    padding: 12px 14px;
    font-size: var(--font-size);line-height: var(--line-height);
    font-family: inherit;
    border-radius: 4px;
    resize: vertical;
    min-height: 400px;
    outline: none;
  }

  .editor-dialog-footer {
    display: flex;
    justify-content: flex-end;
    gap: 8px;
    padding: 12px 16px;
  }

  .editor-dialog-btn {
    padding: 8px 20px;
    border-radius: 4px;
    font-size: var(--font-size);line-height: var(--line-height);
    cursor: pointer;
  }
}

